/* Aula 38 — modelJs: caça-bug (solução) */

const itens = [];

function addItem(texto) {
  const limpo = String(texto ?? '').trim();
  if (!limpo) return;
  itens.push({ id: Date.now(), texto: limpo, done: false });
}

function toggle(id) {
  const numId = Number(id);
  const item = itens.find(x => x.id === numId);
  if (!item) return; // não quebra
  item.done = !item.done;
}

console.log('ANTES add:', itens);
addItem('   ');
addItem('estudar');
console.log('DEPOIS add:', itens);

toggle('id-invalido');
console.log('DEPOIS toggle inválido (não quebra):', itens);
